import '../index.css';

export function NavBar() {
  return (
    <nav
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        width: "100%",
        padding: "10px 40px",
        boxSizing: "border-box",
      }}
    >
       <div style={{ flex: 1, display: "flex", justifyContent: "center",marginLeft:"15px" }}>
        <input
          type="text"
          style={{
            width: "75%",
            height: "25px",
            fontSize: "18px",
            borderRadius: "8px",
            padding: "5px 10px",
          }}
        />
      </div>
      <div style={{ display: "flex", gap: "10px" }}>
        <button className="btnNav">Register</button>
        <button className="btnNav">Login</button>
      </div>
    </nav>
  );
}
